import React, { FC, PropsWithChildren } from 'react';
import { Wrapper, Image } from './styles';

interface IProps {
  image?: string;
  boxColor?: string;
  anchor?: string;
  className?: string;
}

const Hero: FC<PropsWithChildren<IProps>> = ({
  children,
  image,
  boxColor,
  anchor = '',
  className,
}) => (
  <Wrapper boxColor={boxColor} id={anchor} className={className}>
    <Image src={image} loading="lazy" width="1000" height="500" />
    {children}
  </Wrapper>
);

export default Hero;
